mapper.select:
/* 내 문서 목록 조회 myDocuments.selectMyDocList */ SELECT M.DOC_ID , M.USER_ID , M.TMPL_ID , M.AGENT_ID , A.AGENT_NM , M.DOC_NM , M.SVC_TY , M.DOC_STATUS , M.NEW_YN , M.SORT_ORD , M.CREATE_DT , M.MODIFY_DT , I.ICON_CLASS_NM , C.COLOR_HEX FROM TB_MY_DOC M LEFT JOIN TB_AGT A ON M.AGENT_ID = A.AGENT_ID LEFT JOIN TB_ICON I ON A.ICON_ID = I.ICON_ID LEFT JOIN TB_COLOR C ON A.COLOR_ID = C.COLOR_ID WHERE M.USER_ID = #{userId}
AND M.DOC_STATUS = #{docStatus}
AND M.SVC_TY = #{svcTy}
AND M.DOC_NM LIKE CONCAT('%', #{searchDocNm}, '%')
ORDER BY M.CREATE_DT DESC
ORDER BY M.CREATE_DT ASC
ORDER BY M.DOC_NM
ORDER BY M.SORT_ORD
ORDER BY M.CREATE_DT DESC

mapper.update:
/* 신규 문서 맨 앞 등록을 위한 정렬 순서 증가 myDocuments.incrementSortOrdByUserId */
UPDATE TB_MY_DOC
SET SORT_ORD = SORT_ORD + 1
  , MODIFY_DT = NOW()
WHERE USER_ID = #{userId}

mapper.insert:
/* 나의 문서 보고서 저장 myDocuments.saveReport */
INSERT INTO TB_MY_DOC (
      DOC_ID
    , USER_ID
    , TMPL_ID
    , AGENT_ID
    , DOC_NM
    , DOC_HTML
    , ORIGIN_HTML
    , SVC_TY
    , R_CONTENT
    , DOC_STATUS
    , SORT_ORD
    , NEW_YN
    , CREATE_DT
    , MODIFY_DT
) VALUES (
      #{docId}
    , #{userId}
    , #{tmplId, jdbcType=VARCHAR}
    , #{agentId, jdbcType=VARCHAR}
    , #{docNm, jdbcType=VARCHAR}
    , #{docHtml, jdbcType=VARCHAR}
    , #{originHtml, jdbcType=VARCHAR}
    , #{svcTy, jdbcType=VARCHAR}
    , #{rContent, jdbcType=VARCHAR}
    , #{docStatus, jdbcType=VARCHAR}
    , #{sortOrd, jdbcType=INTEGER}
    , #{newYn, jdbcType=CHAR}
    , NOW()
    , NOW()
)
ON DUPLICATE KEY UPDATE
      TMPL_ID      = VALUES(TMPL_ID)
    , AGENT_ID     = VALUES(AGENT_ID)
    , DOC_NM       = VALUES(DOC_NM)
    , DOC_HTML     = VALUES(DOC_HTML)
    , ORIGIN_HTML  = VALUES(ORIGIN_HTML)
    , SVC_TY       = VALUES(SVC_TY)
    , R_CONTENT    = VALUES(R_CONTENT)
    , DOC_STATUS   = VALUES(DOC_STATUS)
    , SORT_ORD     = COALESCE(#{sortOrd, jdbcType=INTEGER}, SORT_ORD)
    , MODIFY_DT    = NOW()

mapper.update:
/* 내 문서 신규 여부 변경 myDocuments.updateNewYn */
UPDATE TB_MY_DOC
SET NEW_YN = #{newYn}
  , MODIFY_DT = NOW()
WHERE DOC_ID = #{docId}
    AND USER_ID = #{userId}
